public enum Output: Codable, Sendable {
    case inputFunctionCallOutputContentItemArray([InputFunctionCallOutputContentItem])
    case string(String)

    public init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let x = try? container.decode([InputFunctionCallOutputContentItem].self) {
            self = .inputFunctionCallOutputContentItemArray(x)
            return
        }
        if let x = try? container.decode(String.self) {
            self = .string(x)
            return
        }
        throw DecodingError.typeMismatch(Output.self, DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Wrong type for Output"))
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .inputFunctionCallOutputContentItemArray(let x):
            try container.encode(x)
        case .string(let x):
            try container.encode(x)
        }
    }
}

