public enum CommandExecutionApprovalDecision: Codable, Sendable {
    case enumeration(FileChangeApprovalDecision)
    case policyAmendmentCommandExecutionApprovalDecision(PolicyAmendmentCommandExecutionApprovalDecision)

    public init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let x = try? container.decode(FileChangeApprovalDecision.self) {
            self = .enumeration(x)
            return
        }
        if let x = try? container.decode(PolicyAmendmentCommandExecutionApprovalDecision.self) {
            self = .policyAmendmentCommandExecutionApprovalDecision(x)
            return
        }
        throw DecodingError.typeMismatch(CommandExecutionApprovalDecision.self, DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Wrong type for CommandExecutionApprovalDecision"))
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .enumeration(let x):
            try container.encode(x)
        case .policyAmendmentCommandExecutionApprovalDecision(let x):
            try container.encode(x)
        }
    }
}

