public enum ApprovalPolicyUnion: Codable, Sendable {
    case askForApprovalGranularAskForApproval(AskForApprovalGranularAskForApproval)
    case enumeration(AskForApprovalEnum)
    case null

    public init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let x = try? container.decode(AskForApprovalEnum.self) {
            self = .enumeration(x)
            return
        }
        if let x = try? container.decode(AskForApprovalGranularAskForApproval.self) {
            self = .askForApprovalGranularAskForApproval(x)
            return
        }
        if container.decodeNil() {
            self = .null
            return
        }
        throw DecodingError.typeMismatch(ApprovalPolicyUnion.self, DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Wrong type for ApprovalPolicyUnion"))
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .askForApprovalGranularAskForApproval(let x):
            try container.encode(x)
        case .enumeration(let x):
            try container.encode(x)
        case .null:
            try container.encodeNil()
        }
    }
}

