public enum TurnErrorCodexErrorInfo: Codable, Sendable {
    case enumeration(CodexErrorInfoEnum)
    case purpleCodexErrorInfo(PurpleCodexErrorInfo)
    case null

    public init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let x = try? container.decode(CodexErrorInfoEnum.self) {
            self = .enumeration(x)
            return
        }
        if let x = try? container.decode(PurpleCodexErrorInfo.self) {
            self = .purpleCodexErrorInfo(x)
            return
        }
        if container.decodeNil() {
            self = .null
            return
        }
        throw DecodingError.typeMismatch(TurnErrorCodexErrorInfo.self, DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Wrong type for TurnErrorCodexErrorInfo"))
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .enumeration(let x):
            try container.encode(x)
        case .purpleCodexErrorInfo(let x):
            try container.encode(x)
        case .null:
            try container.encodeNil()
        }
    }
}

/// Failed to connect to the response SSE stream.
///
/// The response SSE stream disconnected in the middle of a turn before completion.
///
