public enum FunctionCallOutputBody: Codable, Sendable {
    case functionCallOutputContentItemArray([FunctionCallOutputContentItem])
    case string(String)

    public init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let x = try? container.decode([FunctionCallOutputContentItem].self) {
            self = .functionCallOutputContentItemArray(x)
            return
        }
        if let x = try? container.decode(String.self) {
            self = .string(x)
            return
        }
        throw DecodingError.typeMismatch(FunctionCallOutputBody.self, DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Wrong type for FunctionCallOutputBody"))
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .functionCallOutputContentItemArray(let x):
            try container.encode(x)
        case .string(let x):
            try container.encode(x)
        }
    }
}

