public enum ItemContent: Codable, Sendable {
    case inputElement(InputElement)
    case string(String)

    public init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let x = try? container.decode(String.self) {
            self = .string(x)
            return
        }
        if let x = try? container.decode(InputElement.self) {
            self = .inputElement(x)
            return
        }
        throw DecodingError.typeMismatch(ItemContent.self, DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Wrong type for ItemContent"))
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .inputElement(let x):
            try container.encode(x)
        case .string(let x):
            try container.encode(x)
        }
    }
}

