/// The updated thread after applying the rollback, with `turns` populated.
///
/// The ThreadItems stored in each Turn are lossy since we explicitly do not persist all
/// agent interactions, such as command executions. This is the same behavior as
/// `thread/resume`.
// MARK: - ThreadElement
public struct ThreadElement: Codable, Sendable {
    /// Optional random unique nickname assigned to an AgentControl-spawned sub-agent.
    public var agentNickname: String?
    /// Optional role (agent_role) assigned to an AgentControl-spawned sub-agent.
    public var agentRole: String?
    /// Version of the CLI that created the thread.
    public var cliVersion: String
    /// Unix timestamp (in seconds) when the thread was created.
    public var createdAt: Int
    /// Working directory captured for the thread.
    public var cwd: String
    /// Whether the thread is ephemeral and should not be materialized on disk.
    public var ephemeral: Bool
    /// Source thread id when this thread was created by forking another thread.
    public var forkedFromId: String?
    /// Optional Git metadata captured when the thread was created.
    public var gitInfo: GitInfo?
    public var id: String
    /// Model provider used for this thread (for example, 'openai').
    public var modelProvider: String
    /// Optional user-facing thread title.
    public var name: String?
    /// [UNSTABLE] Path to the thread on disk.
    public var path: String?
    /// Usually the first user message in the thread, if available.
    public var preview: String
    /// Origin of the thread (CLI, VSCode, codex exec, codex app-server, etc.).
    public var source: SessionSource
    /// Current runtime status for the thread.
    public var status: ThreadStatus
    /// Only populated on `thread/resume`, `thread/rollback`, `thread/fork`, and `thread/read`
    /// (when `includeTurns` is true) responses. For all other responses and notifications
    /// returning a Thread, the turns field will be an empty list.
    public var turns: [Turn]
    /// Unix timestamp (in seconds) when the thread was last updated.
    public var updatedAt: Int

    public enum CodingKeys: String, CodingKey {
        case agentNickname = "agentNickname"
        case agentRole = "agentRole"
        case cliVersion = "cliVersion"
        case createdAt = "createdAt"
        case cwd = "cwd"
        case ephemeral = "ephemeral"
        case forkedFromId = "forkedFromId"
        case gitInfo = "gitInfo"
        case id = "id"
        case modelProvider = "modelProvider"
        case name = "name"
        case path = "path"
        case preview = "preview"
        case source = "source"
        case status = "status"
        case turns = "turns"
        case updatedAt = "updatedAt"
    }

    public init(agentNickname: String? = nil, agentRole: String? = nil, cliVersion: String, createdAt: Int, cwd: String, ephemeral: Bool, forkedFromId: String? = nil, gitInfo: GitInfo? = nil, id: String, modelProvider: String, name: String? = nil, path: String? = nil, preview: String, source: SessionSource, status: ThreadStatus, turns: [Turn], updatedAt: Int) {
        self.agentNickname = agentNickname
        self.agentRole = agentRole
        self.cliVersion = cliVersion
        self.createdAt = createdAt
        self.cwd = cwd
        self.ephemeral = ephemeral
        self.forkedFromId = forkedFromId
        self.gitInfo = gitInfo
        self.id = id
        self.modelProvider = modelProvider
        self.name = name
        self.path = path
        self.preview = preview
        self.source = source
        self.status = status
        self.turns = turns
        self.updatedAt = updatedAt
    }
}

